# @cctt_verify {"v":2,"sym":"sympy.combinatorics.tests.test_perm_groups.test_centralizer","kind":"function","src_hash":"c43a3e9efe50bda8","in":{"base":"Any"},"out":{"base":"Any","pred":"S.centralizer(Permutation(list(range(2)))).is_subgroup(S) and A.centralizer(Permutation(list(range(5)))).is_subgroup(A) and triv.centralizer(D).is_subgroup(triv) and _verify_centralizer(S, element) and _verify_centralizer(A, element) and _verify_centralizer(D, element) and _verify_centralizer(gp, gp2) and _verify_centralizer(gp, gp2)"},"spec":{"lhs":"test_centralizer()","rhs":"test_centralizer produces the expected output","over":{"base":"Any"},"name":"test_centralizer_correct"},"guarantee":"test_centralizer produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.combinatorics.tests.test_perm_groups.test_centralizer_correct","statement":"Path(test_centralizer(x), test_centralizer produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"fe726e8a385d2c6b"}
def test_centralizer():
    # the centralizer of the trivial group is the entire group
    S = SymmetricGroup(2)
    assert S.centralizer(Permutation(list(range(2)))).is_subgroup(S)
    A = AlternatingGroup(5)
    assert A.centralizer(Permutation(list(range(5)))).is_subgroup(A)
    # a centralizer in the trivial group is the trivial group itself
    triv = PermutationGroup([Permutation([0, 1, 2, 3])])
    D = DihedralGroup(4)
    assert triv.centralizer(D).is_subgroup(triv)
    # brute-force verifications for centralizers of groups
    for i in (4, 5, 6):
        S = SymmetricGroup(i)
        A = AlternatingGroup(i)
        C = CyclicGroup(i)
        D = DihedralGroup(i)
        for gp in (S, A, C, D):
            for gp2 in (S, A, C, D):
                if not gp2.is_subgroup(gp):
                    assert _verify_centralizer(gp, gp2)
    # verify the centralizer for all elements of several groups
    S = SymmetricGroup(5)
    elements = list(S.generate_dimino())
    for element in elements:
        assert _verify_centralizer(S, element)
    A = AlternatingGroup(5)
    elements = list(A.generate_dimino())
    for element in elements:
        assert _verify_centralizer(A, element)
    D = DihedralGroup(7)
    elements = list(D.generate_dimino())
    for element in elements:
        assert _verify_centralizer(D, element)
    # verify centralizers of small groups within small groups
    small = []
    for i in (1, 2, 3):
        small.append(SymmetricGroup(i))
        small.append(AlternatingGroup(i))
        small.append(DihedralGroup(i))
        small.append(CyclicGroup(i))
    for gp in small:
        for gp2 in small:
            if gp.degree == gp2.degree:
                assert _verify_centralizer(gp, gp2)


